// TAPD Keepalive Script (鏀寔鍙岃处鍙?
// 鐢ㄦ硶: node scripts/tapd_keepalive.mjs [zhouyitian|yezhijun]
//   榛樿 zhouyitian锛堝懆浠ュぉ锛?//   鎸囧畾 yezhijun 鍒欎繚娲诲彾鏋濆悰鐨?cookie
//
// Exit codes:
//   0 = success (cookies refreshed)
//   1 = cookie invalid / login expired (need re-login)
//   2 = script error (network, etc.)

import { chromium } from 'playwright';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const WORKSPACE_DIR = path.resolve(__dirname, '..');

// 璐﹀彿鍙傛暟
const ACCOUNT = process.argv[2] || 'zhouyitian';
const LABELS = { zhouyitian: '鍛ㄤ互澶?, yezhijun: '鍙舵灊鍚? };
const label = LABELS[ACCOUNT] || ACCOUNT;

const COOKIES_FILE = ACCOUNT === 'yezhijun'
  ? path.join(WORKSPACE_DIR, 'tapd_cookies_yezhijun.json')
  : path.join(WORKSPACE_DIR, 'tapd_cookies_zhouyitian.json');
const STORAGE_FILE = path.join(WORKSPACE_DIR, `tapd_storage_${ACCOUNT}.json`);
const STATE_FILE = path.join(WORKSPACE_DIR, 'memory', `tapd-keepalive-state-${ACCOUNT}.json`);

const STEALTH_INIT = () => {
  delete navigator.webdriver;
  Object.defineProperty(navigator, 'webdriver', { get: () => false });
  Object.defineProperty(navigator, 'plugins', { get: () => [1, 2, 3, 4, 5] });
  Object.defineProperty(navigator, 'languages', { get: () => ['zh-CN', 'zh'] });
  Object.defineProperty(navigator, 'hardwareConcurrency', { get: () => 8 });
  window.chrome = { runtime: {}, loadTimes: function () {}, csi: function () {}, app: {} };
};

function log(msg) {
  console.log(`[${new Date().toISOString()}] ${msg}`);
}

function writeState(state) {
  try {
    fs.mkdirSync(path.dirname(STATE_FILE), { recursive: true });
    fs.writeFileSync(STATE_FILE, JSON.stringify(state, null, 2));
  } catch (e) {
    console.error('Failed to write state:', e.message);
  }
}

async function main() {
  if (!fs.existsSync(COOKIES_FILE)) {
    log(`[${label}] ERROR: cookies file not found: ${COOKIES_FILE}`);
    writeState({ ok: false, error: 'cookies_missing', at: new Date().toISOString(), account: ACCOUNT });
    process.exit(1);
  }

  const oldCookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));
  log(`[${label}] Loaded ${oldCookies.length} cookies`);

  const browser = await chromium.launch({
    headless: true,
    args: ['--no-sandbox', '--disable-blink-features=AutomationControlled'],
  });
  const ctx = await browser.newContext({
    locale: 'zh-CN',
    viewport: { width: 1920, height: 1080 },
    userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/125.0.0.0 Safari/537.36',
  });

