node -e "
const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.launch({ headless: false, args: ['--no-sandbox'] });
  const ctx = await browser.newContext({ locale: 'zh-CN', viewport: { width: 1280, height: 800 } });
  const page = await ctx.newPage();
  await page.goto('https://www.tapd.cn/cloud_logins/login', { waitUntil: 'networkidle' });
  console.log('TAPD登录页已打开，请扫码登录...');
  // 检测是否已登录
  try {
    await page.waitForURL('https://www.tapd.cn/**', { timeout: 300000 });
    // 等待跳转到TAPD主站
    await page.waitForTimeout(3000);
    // 获取cookies并保存
    const cookies = await ctx.cookies();
    const fs = require('fs');
    fs.writeFileSync('tapd_cookies_yezhijun.json', JSON.stringify(cookies, null, 2));
    console.log('登录成功，cookies已保存');
  } catch (e) {
    console.log('等待超时或未检测到登录成功');
  }
  await browser.close();
})().catch(e => { console.error(e); process.exit(1); });
"
